import { createClient } from 'https://esm.sh/@supabase/supabase-js@2';

const corsHeaders = {
  'Access-Control-Allow-Origin': '*',
  'Access-Control-Allow-Headers':
    'authorization, x-client-info, apikey, content-type, x-api-key',
};

async function hashKey(key: string): Promise<string> {
  const encoder = new TextEncoder();
  const data = encoder.encode(key);
  const hash = await crypto.subtle.digest('SHA-256', data);
  return Array.from(new Uint8Array(hash))
    .map((b) => b.toString(16).padStart(2, '0'))
    .join('');
}

Deno.serve(async (req) => {
  if (req.method === 'OPTIONS') {
    return new Response('ok', { headers: corsHeaders });
  }

  try {
    const supabase = createClient(
      Deno.env.get('SUPABASE_URL')!,
      Deno.env.get('SUPABASE_SERVICE_ROLE_KEY')!
    );

    // Authenticate via API key
    const apiKey = req.headers.get('X-API-Key');
    if (!apiKey) {
      return new Response(JSON.stringify({ error: 'Missing API key' }), {
        status: 401,
        headers: { ...corsHeaders, 'Content-Type': 'application/json' },
      });
    }

    const keyHash = await hashKey(apiKey);
    const { data: keyRecord } = await supabase
      .from('api_keys')
      .select('*, merchants(plan)')
      .eq('key_hash', keyHash)
      .eq('is_active', true)
      .single();

    if (!keyRecord) {
      return new Response(JSON.stringify({ error: 'Invalid API key' }), {
        status: 401,
        headers: { ...corsHeaders, 'Content-Type': 'application/json' },
      });
    }

    if ((keyRecord as any).merchants?.plan !== 'business') {
      return new Response(
        JSON.stringify({ error: 'Business plan required' }),
        {
          status: 403,
          headers: { ...corsHeaders, 'Content-Type': 'application/json' },
        }
      );
    }

    const merchantId = keyRecord.merchant_id;

    // Update last_used_at
    await supabase
      .from('api_keys')
      .update({ last_used_at: new Date().toISOString() })
      .eq('id', keyRecord.id);

    // Route requests
    const url = new URL(req.url);
    const path = url.pathname.replace(/^\/api-v1\/?/, '').replace(/\/$/, '');
    const method = req.method;

    const json = (data: any, status = 200) =>
      new Response(JSON.stringify(data), {
        status,
        headers: { ...corsHeaders, 'Content-Type': 'application/json' },
      });

    // GET /programs — List merchant's loyalty programs
    if (method === 'GET' && path === 'programs') {
      const { data } = await supabase
        .from('loyalty_programs')
        .select('*')
        .eq('merchant_id', merchantId);
      return json({ data });
    }

    // GET /clients — List merchant's clients via customer_cards
    if (method === 'GET' && path === 'clients') {
      const { data } = await supabase
        .from('customer_cards')
        .select('*, customers(*), loyalty_programs!inner(merchant_id)')
        .eq('loyalty_programs.merchant_id', merchantId);
      return json({ data });
    }

    // POST /stamps — Add stamp to a customer card
    if (method === 'POST' && path === 'stamps') {
      const body = await req.json();
      if (!body.card_id) return json({ error: 'Missing card_id' }, 400);
      const count = body.count ?? 1;

      const { data: card } = await supabase
        .from('customer_cards')
        .select('*, loyalty_programs!inner(merchant_id)')
        .eq('id', body.card_id)
        .eq('loyalty_programs.merchant_id', merchantId)
