      await supabase
        .from('customer_cards')
        .update({
          current_stamps: card.current_stamps + count,
          last_activity: new Date().toISOString(),
        })
        .eq('id', card.id);

      await supabase.from('transactions').insert({
        card_id: card.id,
        type: 'stamp_add',
        value: count,
        validated_by: 'manual',
      });

      return json({ success: true });
    }

    // POST /points — Add points to a customer card
    if (method === 'POST' && path === 'points') {
      const body = await req.json();
      if (!body.card_id || !body.points) {
        return json({ error: 'Missing card_id or points' }, 400);
      }

      const { data: card } = await supabase
        .from('customer_cards')
        .select('*, loyalty_programs!inner(merchant_id)')
        .eq('id', body.card_id)
        .eq('loyalty_programs.merchant_id', merchantId)
        .single();
      if (!card) return json({ error: 'Card not found' }, 404);

      await supabase
        .from('customer_cards')
        .update({
          current_points: card.current_points + body.points,
          last_activity: new Date().toISOString(),
        })
        .eq('id', card.id);

      await supabase.from('transactions').insert({
        card_id: card.id,
        type: 'points_add',
        value: body.points,
        validated_by: 'manual',
      });

      return json({ success: true });
    }

