      const { data } = await supabase
        .from('merchant_kpis')
        .select('*')
        .eq('merchant_id', merchantId)
        .single();
      return json({ data });
    }

    return json({ error: 'Not found' }, 404);
  } catch (err) {
    return new Response(JSON.stringify({ error: (err as Error).message }), {
      status: 500,
      headers: { ...corsHeaders, 'Content-Type': 'application/json' },
    });
  }
});


