    if (referral.referrer_id === new_customer_id) {
      return new Response(
        JSON.stringify({ error: 'Cannot use your own referral code' }),
        { status: 400, headers: { ...corsHeaders, 'Content-Type': 'application/json' } }
      );
    }

    // Update referral with referred user
    await supabase
      .from('referrals')
      .update({
        referred_id: new_customer_id,
        status: 'completed',
        reward_given: true,
      })
      .eq('id', referral.id);

    // Award 50 bonus points to both referrer and referred user on their first card
    const bonusPoints = 50;

    // Get first card for referrer
    const { data: referrerCard } = await supabase
      .from('customer_cards')
      .select('id, current_points')
      .eq('customer_id', referral.referrer_id)
      .order('created_at', { ascending: true })
      .limit(1)
      .single();

