        .from('customer_cards')
        .update({ current_points: referrerCard.current_points + bonusPoints })
        .eq('id', referrerCard.id);

      await supabase.from('transactions').insert({
        card_id: referrerCard.id,
        type: 'points_add',
        value: bonusPoints,
        validated_by: 'manual',
      });
    }

    // Get first card for referred user
    const { data: referredCard } = await supabase
      .from('customer_cards')
      .select('id, current_points')
      .eq('customer_id', new_customer_id)
      .order('created_at', { ascending: true })
