import { createClient } from 'https://esm.sh/@supabase/supabase-js@2';

const corsHeaders = {
  'Access-Control-Allow-Origin': '*',
  'Access-Control-Allow-Headers': 'authorization, x-client-info, apikey, content-type',
};

/**
 * Shuffle an array in-place using Fisher-Yates and return it.
 */
function shuffle<T>(arr: T[]): T[] {
  for (let i = arr.length - 1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i + 1));
    [arr[i], arr[j]] = [arr[j], arr[i]];
  }
  return arr;
}

Deno.serve(async (req) => {
  if (req.method === 'OPTIONS') return new Response('ok', { headers: corsHeaders });

  try {
    const supabase = createClient(
      Deno.env.get('SUPABASE_URL')!,
      Deno.env.get('SUPABASE_SERVICE_ROLE_KEY')!
    );

    const { campaign_id, ab_test, variant_b_id } = await req.json();
    if (!campaign_id) return new Response(JSON.stringify({ error: 'Missing campaign_id' }), { status: 400, headers: corsHeaders });

    const { data: campaign } = await supabase.from('campaigns').select('*').eq('id', campaign_id).single();
    if (!campaign) return new Response(JSON.stringify({ error: 'Campaign not found' }), { status: 404, headers: corsHeaders });

    // Fetch filtered audience (shared for both modes)
    const { data: cards } = await supabase
      .from('customer_cards')
      .select('customer_id, created_at, last_activity, tier, customers(push_token), loyalty_programs!inner(merchant_id)')
      .eq('loyalty_programs.merchant_id', campaign.merchant_id);

    const now = new Date();
    const filteredCards = (cards ?? []).filter((c: any) => {
      switch (campaign.target_segment) {
        case 'new': {
          if (!c.created_at) return false;
          const createdAt = new Date(c.created_at);
          const daysSinceCreation = (now.getTime() - createdAt.getTime()) / (1000 * 60 * 60 * 24);
          return daysSinceCreation <= 30;
        }
        case 'inactive': {
          if (!c.last_activity) return true;
          const lastActivity = new Date(c.last_activity);
          const daysSinceActivity = (now.getTime() - lastActivity.getTime()) / (1000 * 60 * 60 * 24);
          return daysSinceActivity > 14;
        }
        case 'vip': {
          const tier = (c.tier ?? '').toLowerCase();
          return tier === 'gold' || tier === 'vip';
        }
        case 'all':
        default:
          return true;
      }
    });

    // ---------- A/B Test path ----------
    if (ab_test && variant_b_id) {
      const { data: campaignB } = await supabase.from('campaigns').select('*').eq('id', variant_b_id).single();
      if (!campaignB) return new Response(JSON.stringify({ error: 'Variant B campaign not found' }), { status: 404, headers: corsHeaders });

      // Shuffle and split audience 50/50
      shuffle(filteredCards);
      const midpoint = Math.ceil(filteredCards.length / 2);
      const groupA = filteredCards.slice(0, midpoint);
      const groupB = filteredCards.slice(midpoint);

      const tokensA = groupA.map((c: any) => c.customers?.push_token).filter(Boolean) as string[];
      const tokensB = groupB.map((c: any) => c.customers?.push_token).filter(Boolean) as string[];

      // Send variant A
      if (tokensA.length) {
        const messagesA = tokensA.map((token) => ({
          to: token,
          title: campaign.title,
          body: campaign.body,
          data: { campaign_id: campaign.id, type: 'campaign' },
        }));
        await fetch('https://exp.host/--/api/v2/push/send', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify(messagesA),
        });
      }

      // Send variant B
      if (tokensB.length) {
        const messagesB = tokensB.map((token) => ({
          to: token,
          title: campaignB.title,
          body: campaignB.body,
          data: { campaign_id: campaignB.id, type: 'campaign' },
        }));
        await fetch('https://exp.host/--/api/v2/push/send', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify(messagesB),
        });
      }

      // Record notifications for variant A
      const notificationsA = groupA.map((c: any) => ({
        customer_id: c.customer_id,
        campaign_id: campaign.id,
        title: campaign.title,
        body: campaign.body,
        type: 'campaign' as const,
      }));

      // Record notifications for variant B
      const notificationsB = groupB.map((c: any) => ({
        customer_id: c.customer_id,
        campaign_id: campaignB.id,
        title: campaignB.title,
        body: campaignB.body,
        type: 'campaign' as const,
      }));

      const allNotifications = [...notificationsA, ...notificationsB];
      if (allNotifications.length) {
        await supabase.from('notifications').insert(allNotifications);
      }

      // Mark both campaigns as sent
      const sentAt = new Date().toISOString();
      await supabase.from('campaigns').update({ status: 'sent', sent_at: sentAt }).eq('id', campaign.id);
      await supabase.from('campaigns').update({ status: 'sent', sent_at: sentAt }).eq('id', campaignB.id);

      return new Response(
        JSON.stringify({ sent: tokensA.length + tokensB.length, variant_a: tokensA.length, variant_b: tokensB.length }),
        { status: 200, headers: { ...corsHeaders, 'Content-Type': 'application/json' } }
      );
    }

    // ---------- Standard (non-A/B) path ----------
    const tokens = filteredCards
      .map((c: any) => c.customers?.push_token)
      .filter(Boolean) as string[];

    if (!tokens.length) {
      return new Response(JSON.stringify({ sent: 0 }), { status: 200, headers: { ...corsHeaders, 'Content-Type': 'application/json' } });
    }

    const messages = tokens.map((token) => ({
      to: token,
      title: campaign.title,
      body: campaign.body,
      data: { campaign_id: campaign.id, type: 'campaign' },
    }));

    await fetch('https://exp.host/--/api/v2/push/send', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(messages),
    });

    const notifications = filteredCards.map((c: any) => ({
      customer_id: c.customer_id,
      campaign_id: campaign.id,
      title: campaign.title,
      body: campaign.body,
      type: 'campaign' as const,
    }));

    if (notifications.length) {
      await supabase.from('notifications').insert(notifications);
    }

    await supabase.from('campaigns').update({
      status: 'sent',
      sent_at: new Date().toISOString(),
    }).eq('id', campaign.id);

    return new Response(JSON.stringify({ sent: tokens.length }), {
      status: 200,
      headers: { ...corsHeaders, 'Content-Type': 'application/json' },
    });

  } catch (err) {
    return new Response(JSON.stringify({ error: (err as Error).message }), { status: 500, headers: corsHeaders });
  }
