'use client';
import { useEffect, useState } from 'react';
import { createClient } from '@/lib/supabase/client';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { Textarea } from '@/components/ui/textarea';
import Link from 'next/link';

export default function SettingsPage() {
  const supabase = createClient();
  const [merchant, setMerchant] = useState<any>(null);
  const [loading, setLoading] = useState(false);
  const [name, setName] = useState('');
  const [address, setAddress] = useState('');
  const [category, setCategory] = useState('');
  const [phone, setPhone] = useState('');
  const [hours, setHours] = useState('');
  const [logoUrl, setLogoUrl] = useState('');
  const [message, setMessage] = useState('');

  useEffect(() => {
    fetchMerchant();
  }, []);

  async function fetchMerchant() {
    const { data: { user } } = await supabase.auth.getUser();
    if (!user) return;
    const { data } = await supabase.from('merchants').select('*').eq('user_id', user.id).single();
    if (data) {
      setMerchant(data);
      setName(data.name || '');
      setAddress(data.address || '');
      setCategory(data.category || '');
      setPhone(data.phone || '');
      setHours(data.opening_hours || '');
      setLogoUrl(data.logo_url || '');
    }
  }

  async function handleSave() {
    if (!merchant) return;
    setLoading(true);
    await supabase.from('merchants').update({
      name, address, category, phone, opening_hours: hours, logo_url: logoUrl,
    }).eq('id', merchant.id);
    setMessage('Settings saved!');
    setLoading(false);
    setTimeout(() => setMessage(''), 3000);
  }

  async function handleLogoUpload(e: React.ChangeEvent<HTMLInputElement>) {
    const file = e.target.files?.[0];
    if (!file || !merchant) return;
    const path = `${merchant.id}/${Date.now()}-${file.name}`;
    const { error } = await supabase.storage.from('logos').upload(path, file);
    if (error) return;
    const { data: { publicUrl } } = supabase.storage.from('logos').getPublicUrl(path);
    setLogoUrl(publicUrl);
  }

  async function handleDeleteAccount() {
    if (!confirm('Are you sure you want to delete your account? This action cannot be undone.')) return;
    if (!merchant) return;
    await supabase.from('merchants').delete().eq('id', merchant.id);
    await supabase.auth.signOut();
    window.location.href = '/login';
  }

  return (
    <div className="space-y-6 max-w-2xl">
      <h1 className="text-2xl font-bold">Settings</h1>
      {message && <p className="text-green-600 text-sm">{message}</p>}

      <Card>
        <CardHeader><CardTitle>Business Logo</CardTitle></CardHeader>
        <CardContent className="space-y-3">
          {logoUrl && <img src={logoUrl} alt="Logo" className="w-24 h-24 object-cover rounded" />}
          <Input type="file" accept="image/*" onChange={handleLogoUpload} />
        </CardContent>
      </Card>

      <Card>
        <CardHeader><CardTitle>Store Information</CardTitle></CardHeader>
        <CardContent className="space-y-3">
          <div><Label>Store Name</Label><Input value={name} onChange={e => setName(e.target.value)} /></div>
          <div><Label>Address</Label><Input value={address} onChange={e => setAddress(e.target.value)} /></div>
          <div><Label>Category</Label><Input value={category} onChange={e => setCategory(e.target.value)} placeholder="e.g. Restaurant, Retail, Cafe" /></div>
          <div><Label>Phone</Label><Input value={phone} onChange={e => setPhone(e.target.value)} /></div>
          <div><Label>Opening Hours</Label><Textarea value={hours} onChange={e => setHours(e.target.value)} placeholder={'Mon-Fri: 9:00-18:00\nSat: 10:00-16:00'} /></div>
          <Button onClick={handleSave} disabled={loading}>{loading ? 'Saving...' : 'Save Changes'}</Button>
        </CardContent>
      </Card>

      <Card>
        <CardHeader><CardTitle>Manage</CardTitle></CardHeader>
        <CardContent className="space-y-2">
          <Link href="/settings/locations" className="block text-blue-600 hover:underline">Manage Locations &rarr;</Link>
          <Link href="/settings/api" className="block text-blue-600 hover:underline">API Keys (Business plan) &rarr;</Link>
        </CardContent>
      </Card>

      <Card className="border-red-200">
        <CardHeader><CardTitle className="text-red-600">Danger Zone</CardTitle></CardHeader>
        <CardContent>
          <p className="text-sm text-gray-500 mb-3">Permanently delete your merchant account and all associated data.</p>
          <Button variant="destructive" onClick={handleDeleteAccount}>Delete Account</Button>
        </CardContent>
      </Card>
    </div>
  );
}


