'use client';
import { useState } from 'react';
import { useRouter } from 'next/navigation';
import { createClient } from '@/lib/supabase/client';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Textarea } from '@/components/ui/textarea';
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from '@/components/ui/select';

type Segment = 'all' | 'new' | 'inactive' | 'vip';

const SEGMENT_LABELS: Record<Segment, string> = {
  all: 'All Clients',
  new: 'New Clients (joined < 30 days)',
  inactive: 'Inactive Clients (no activity > 14 days)',
  vip: 'VIP Clients (Gold / VIP tier)',
};

const SEGMENT_BUTTON_LABELS: Record<Segment, string> = {
  all: 'Send to All Clients',
  new: 'Send to New Clients',
  inactive: 'Send to Inactive Clients',
  vip: 'Send to VIP Clients',
};

export function CampaignForm({ merchantId }: { merchantId: string }) {
  const [title, setTitle] = useState('');
  const [body, setBody] = useState('');
  const [segment, setSegment] = useState<Segment>('all');
  const [loading, setLoading] = useState(false);
  const [abEnabled, setAbEnabled] = useState(false);
  const [titleB, setTitleB] = useState('');
  const [bodyB, setBodyB] = useState('');
  const router = useRouter();
  const supabase = createClient();

  async function handleSend(e: React.FormEvent) {
    e.preventDefault();
    setLoading(true);

    try {
      if (abEnabled) {
        // --- A/B Test: create two campaign rows ---
        const { data: campaignA, error: errA } = await supabase
          .from('campaigns')
          .insert({
            merchant_id: merchantId,
            title,
            body,
            type: 'push',
            target_segment: segment,
            status: 'draft',
            variant: 'A',
          })
          .select()
          .single();

        if (errA || !campaignA) {
          setLoading(false);
          return;
        }

        const { data: campaignB, error: errB } = await supabase
          .from('campaigns')
          .insert({
            merchant_id: merchantId,
            title: titleB,
            body: bodyB,
            type: 'push',
            target_segment: segment,
            status: 'draft',
            variant: 'B',
            parent_campaign_id: campaignA.id,
          })
          .select()
          .single();

        if (errB || !campaignB) {
          setLoading(false);
          return;
        }

        await supabase.functions.invoke('send-push', {
          body: {
            campaign_id: campaignA.id,
            ab_test: true,
            variant_b_id: campaignB.id,
          },
        });
      } else {
        // --- Standard single campaign ---
        const { data: campaign, error } = await supabase
          .from('campaigns')
          .insert({
            merchant_id: merchantId,
            title,
            body,
            type: 'push',
            target_segment: segment,
            status: 'draft',
          })
          .select()
          .single();

        if (error || !campaign) {
          setLoading(false);
          return;
        }

        await supabase.functions.invoke('send-push', {
          body: { campaign_id: campaign.id },
        });
      }

      setTitle('');
      setBody('');
      setTitleB('');
      setBodyB('');
      setSegment('all');
      setAbEnabled(false);
      setLoading(false);
      router.refresh();
    } catch {
      setLoading(false);
    }
  }

  return (
    <form onSubmit={handleSend} className="space-y-4 max-w-lg p-4 border rounded-lg">
      <h3 className="font-semibold">Send Push Notification</h3>

      {/* A/B toggle */}
      <div className="flex items-center gap-2">
        <input
          id="ab-toggle"
          type="checkbox"
          checked={abEnabled}
          onChange={(e) => setAbEnabled(e.target.checked)}
          className="h-4 w-4 rounded border-gray-300 text-indigo-600 focus:ring-indigo-500"
        />
        <Label htmlFor="ab-toggle">Enable A/B Test</Label>
      </div>

      {abEnabled ? (
        <>
          {/* Variant A */}
          <fieldset className="space-y-2 border rounded-md p-3">
            <legend className="px-1 text-sm font-medium text-indigo-700">
              Variant A
            </legend>
            <div>
              <Label>Title (A)</Label>
              <Input
                value={title}
                onChange={(e) => setTitle(e.target.value)}
                placeholder="e.g. Weekend Special!"
                required
              />
            </div>
            <div>
              <Label>Message (A)</Label>
              <Textarea
                value={body}
                onChange={(e) => setBody(e.target.value)}
                placeholder="e.g. 20% off all items this weekend!"
                required
              />
            </div>
          </fieldset>

          {/* Variant B */}
          <fieldset className="space-y-2 border rounded-md p-3">
            <legend className="px-1 text-sm font-medium text-indigo-700">
              Variant B
            </legend>
            <div>
