import { supabase } from '../lib/supabase';
import { useAuthStore } from '../lib/store';

export function useAuth() {
  const { setSession, setProfile, reset } = useAuthStore();

  async function signInWithEmail(email: string, password: string) {
    const { data, error } = await supabase.auth.signInWithPassword({ email, password });
    if (error) throw error;
    setSession(data.session);
    await fetchProfile(data.session.user.id);
  }

  async function signUpWithEmail(email: string, password: string, name: string) {
    const { data, error } = await supabase.auth.signUp({ email, password, options: { data: { name } } });
    if (error) throw error;
    if (data.session) {
      setSession(data.session);
      const { error: profileError } = await supabase.from('customers').insert({
        id: data.session.user.id,
        email,
        name,
      });
      if (profileError) console.error('Profile creation error:', profileError);

      // Generate and insert referral code for the new user
      const code = `${name.slice(0, 4).toUpperCase()}${Math.random().toString(36).slice(2, 6).toUpperCase()}`;
      const { error: referralError } = await supabase.from('referrals').insert({
        referrer_id: data.session.user.id,
        referral_code: code,
      });
      if (referralError) console.error('Referral code creation error:', referralError);

      await fetchProfile(data.session.user.id);
    }
  }

  async function fetchProfile(userId: string) {
    const { data } = await supabase.from('customers').select('*').eq('id', userId).single();
    if (data) setProfile(data);
  }

  async function signOut() {
    await supabase.auth.signOut();
    reset();
  }

  return { signInWithEmail, signUpWithEmail, signOut, fetchProfile };
}

