export default function LocationsPage() {
  const supabase = createClient();
  const [locations, setLocations] = useState<Location[]>([]);
  const [merchantId, setMerchantId] = useState<string | null>(null);
  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState(false);

  // Form state
  const [name, setName] = useState('');
  const [address, setAddress] = useState('');
  const [latitude, setLatitude] = useState('');
  const [longitude, setLongitude] = useState('');

  const fetchLocations = useCallback(async (mId: string) => {
    const { data } = await supabase
      .from('merchant_locations')
      .select('*')
      .eq('merchant_id', mId)
      .order('created_at', { ascending: false });
    setLocations(data ?? []);
  }, [supabase]);

  useEffect(() => {
    async function init() {
      const { data: { user } } = await supabase.auth.getUser();
      if (!user) return;
      const { data: merchant } = await supabase
        .from('merchants')
        .select('id')
        .eq('user_id', user.id)
        .single();
      if (!merchant) return;
      setMerchantId(merchant.id);
      await fetchLocations(merchant.id);
      setLoading(false);
    }
    init();
  }, [supabase, fetchLocations]);

  async function handleAdd() {
    if (!merchantId || !name.trim()) return;
    setSaving(true);
    const { error } = await supabase.from('merchant_locations').insert({
      merchant_id: merchantId,
      name: name.trim(),
      address: address.trim() || null,
      latitude: latitude ? parseFloat(latitude) : null,
      longitude: longitude ? parseFloat(longitude) : null,
    });
    if (error) {
      console.error('Failed to add location:', error.message);
    } else {
      setName('');
      setAddress('');
      setLatitude('');
      setLongitude('');
      await fetchLocations(merchantId);
    }
    setSaving(false);
  }

  async function handleToggleActive(location: Location) {
    const { error } = await supabase
      .from('merchant_locations')
      .update({ is_active: !location.is_active })
      .eq('id', location.id);
    if (error) {
      console.error('Failed to toggle location:', error.message);
    } else if (merchantId) {
      await fetchLocations(merchantId);
    }
  }

  async function handleDelete(locationId: string) {
    if (!confirm('Are you sure you want to delete this location?')) return;
    const { error } = await supabase
      .from('merchant_locations')
      .delete()
      .eq('id', locationId);
    if (error) {
      console.error('Failed to delete location:', error.message);
    } else if (merchantId) {
      await fetchLocations(merchantId);
    }
  }

  if (loading) {
    return <p className="text-gray-500">Loading locations...</p>;
  }

  return (
    <div>
      <h2 className="text-2xl font-bold mb-6">Locations</h2>

      <div className="grid gap-6 lg:grid-cols-2">
