import { createClient } from '@/lib/supabase/server';
import { redirect } from 'next/navigation';
import {
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableHeader,
  TableRow,
} from '@/components/ui/table';
import { Badge } from '@/components/ui/badge';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';

interface Campaign {
  id: string;
  title: string;
  body: string;
  variant: string | null;
  parent_campaign_id: string | null;
  opens: number;
  clicks: number;
  status: string;
  sent_at: string | null;
  created_at: string;
}

interface ABPair {
  a: Campaign;
  b: Campaign;
  winnerOpen: 'A' | 'B' | 'tie';
  winnerClick: 'A' | 'B' | 'tie';
}

function rate(numerator: number, denominator: number): string {
  if (denominator === 0) return '0.0%';
  return ((numerator / denominator) * 100).toFixed(1) + '%';
}

function determineWinner(valA: number, valB: number): 'A' | 'B' | 'tie' {
  if (valA > valB) return 'A';
  if (valB > valA) return 'B';
  return 'tie';
}

export default async function ABResultsPage() {
  const supabase = await createClient();
  const {
    data: { user },
  } = await supabase.auth.getUser();
  if (!user) redirect('/login');

  const { data: merchant } = await supabase
    .from('merchants')
    .select('id')
    .eq('user_id', user.id)
    .single();

  if (!merchant) redirect('/login');

  // Fetch all campaigns that are part of an A/B test
  const { data: abCampaigns } = await supabase
    .from('campaigns')
    .select('*')
    .eq('merchant_id', merchant.id)
    .not('variant', 'is', null)
    .order('created_at', { ascending: false });

  // Group into pairs: variant A (parent) + variant B (child referencing parent)
  const pairs: ABPair[] = [];
  const campaignMap = new Map<string, Campaign>();
  for (const c of (abCampaigns ?? []) as Campaign[]) {
    campaignMap.set(c.id, c);
  }

  // Find all A variants (variant === 'A' and no parent_campaign_id)
  for (const c of (abCampaigns ?? []) as Campaign[]) {
    if (c.variant === 'A' && !c.parent_campaign_id) {
      // Find its B child
      const bChild = (abCampaigns ?? []).find(
        (b: Campaign) => b.parent_campaign_id === c.id && b.variant === 'B'
      ) as Campaign | undefined;
      if (bChild) {
        // Simple comparison using opens and clicks stored on the campaign row
        // In a production app you would count notifications with read_at, etc.
        const totalA = Math.max(c.opens + c.clicks, 1);
        const totalB = Math.max(bChild.opens + bChild.clicks, 1);
        pairs.push({
          a: c,
          b: bChild,
          winnerOpen: determineWinner(c.opens, bChild.opens),
          winnerClick: determineWinner(c.clicks, bChild.clicks),
        });
      }
    }
  }

  return (
    <div className="space-y-6">
      <h1 className="text-2xl font-bold">A/B Test Results</h1>

      {pairs.length === 0 ? (
        <p className="text-gray-500">
          No A/B tests found. Create one from the Campaigns page.
        </p>
      ) : (
        <div className="space-y-6">
          {pairs.map((pair) => (
            <Card key={pair.a.id}>
              <CardHeader>
                <CardTitle className="text-base">
                  A/B Test &mdash;{' '}
                  {pair.a.sent_at
                    ? new Date(pair.a.sent_at).toLocaleDateString()
                    : 'Draft'}
                </CardTitle>
              </CardHeader>
              <CardContent>
                <Table>
                  <TableHeader>
                    <TableRow>
                      <TableHead>Metric</TableHead>
                      <TableHead>Variant A</TableHead>
                      <TableHead>Variant B</TableHead>
                      <TableHead>Winner</TableHead>
                    </TableRow>
                  </TableHeader>
                  <TableBody>
                    <TableRow>
                      <TableCell className="font-medium">Title</TableCell>
                      <TableCell>{pair.a.title}</TableCell>
                      <TableCell>{pair.b.title}</TableCell>
                      <TableCell />
                    </TableRow>
                    <TableRow>
                      <TableCell className="font-medium">Opens</TableCell>
                      <TableCell
                        className={
                          pair.winnerOpen === 'A'
                            ? 'text-green-600 font-semibold'
                            : ''
                        }
                      >
                        {pair.a.opens}
                      </TableCell>
                      <TableCell
                        className={
                          pair.winnerOpen === 'B'
                            ? 'text-green-600 font-semibold'
                            : ''
                        }
                      >
                        {pair.b.opens}
                      </TableCell>
                      <TableCell>
                        {pair.winnerOpen === 'tie' ? (
                          <Badge variant="secondary">Tie</Badge>
                        ) : (
                          <Badge variant="default">
                            Variant {pair.winnerOpen}
                          </Badge>
                        )}
                      </TableCell>
                    </TableRow>
                    <TableRow>
                      <TableCell className="font-medium">Clicks</TableCell>
                      <TableCell
                        className={
                          pair.winnerClick === 'A'
                            ? 'text-green-600 font-semibold'
                            : ''
                        }
                      >
                        {pair.a.clicks}
                      </TableCell>
                      <TableCell
                        className={
                          pair.winnerClick === 'B'
                            ? 'text-green-600 font-semibold'
                            : ''
                        }
                      >
                        {pair.b.clicks}
                      </TableCell>
                      <TableCell>
                        {pair.winnerClick === 'tie' ? (
                          <Badge variant="secondary">Tie</Badge>
                        ) : (
                          <Badge variant="default">
                            Variant {pair.winnerClick}
                          </Badge>
                        )}
                      </TableCell>
                    </TableRow>
                    <TableRow>
                      <TableCell className="font-medium">Open Rate</TableCell>
                      <TableCell>
                        {rate(pair.a.opens, pair.a.opens + pair.a.clicks)}
                      </TableCell>
                      <TableCell>
                        {rate(pair.b.opens, pair.b.opens + pair.b.clicks)}
                      </TableCell>
                      <TableCell />
                    </TableRow>
                    <TableRow>
                      <TableCell className="font-medium">Click Rate</TableCell>
                      <TableCell>
                        {rate(pair.a.clicks, pair.a.opens + pair.a.clicks)}
                      </TableCell>
                      <TableCell>
                        {rate(pair.b.clicks, pair.b.opens + pair.b.clicks)}
                      </TableCell>
                      <TableCell />
                    </TableRow>
                  </TableBody>
                </Table>
              </CardContent>
            </Card>
          ))}
        </div>
      )}
    </div>
  );
}

