'use client';

import { useState } from 'react';
import { useRouter } from 'next/navigation';
import { createClient } from '@/lib/supabase/client';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from '@/components/ui/select';
import { QRCode } from 'react-qrcode-logo';

interface Props {
  merchantId: string;
  programs: { id: string; name: string; type: string }[];
  existingCodes: any[];
}

export function QrGenerator({ merchantId, programs, existingCodes }: Props) {
  const [selectedProgram, setSelectedProgram] = useState('');
  const [label, setLabel] = useState('');
  const [loading, setLoading] = useState(false);
  const router = useRouter();
  const supabase = createClient();

  async function handleCreate() {
    if (!selectedProgram) return;
    setLoading(true);

    const { error } = await supabase.from('qr_codes').insert({
      merchant_id: merchantId,
      program_id: selectedProgram,
      label: label || null,
    });

    if (error) {
      console.error('Failed to create QR code:', error.message);
    }

    setLabel('');
    setSelectedProgram('');
    setLoading(false);
    router.refresh();
  }

  function buildQrPayload(code: any) {
    return JSON.stringify({
      type: 'loyalty_scan',
      qr_id: code.id,
      secret: code.secret_key,
    });
  }

  return (
    <div className="grid gap-6 lg:grid-cols-2">
      <div>
        <h3 className="font-semibold mb-3">Generate New QR</h3>
        <div className="space-y-3 p-4 border rounded-lg">
          <div>
            <Label>Program</Label>
            <Select value={selectedProgram} onValueChange={setSelectedProgram}>
              <SelectTrigger>
                <SelectValue placeholder="Select program" />
              </SelectTrigger>
              <SelectContent>
                {programs.map((p) => (
                  <SelectItem key={p.id} value={p.id}>
                    {p.name}
                  </SelectItem>
                ))}
              </SelectContent>
            </Select>
          </div>
          <div>
            <Label>Label (optional)</Label>
            <Input
              value={label}
              onChange={(e) => setLabel(e.target.value)}
              placeholder="e.g. Counter 1"
            />
          </div>
          <Button
            onClick={handleCreate}
            disabled={loading || !selectedProgram}
          >
            {loading ? 'Creating...' : 'Generate QR Code'}
          </Button>
        </div>
      </div>
      <div>
        <h3 className="font-semibold mb-3">Existing QR Codes</h3>
        {!existingCodes.length ? (
          <p className="text-gray-500">No QR codes yet.</p>
        ) : (
          <div className="space-y-4">
            {existingCodes.map((code) => (
              <div
                key={code.id}
                className="p-4 border rounded-lg flex items-center gap-4"
              >
                <QRCode value={buildQrPayload(code)} size={100} />
                <div>
                  <p className="font-medium">{code.label || 'Unlabeled'}</p>
                  <p className="text-sm text-gray-500">
                    {code.loyalty_programs?.name}
                  </p>
                  <p className="text-xs text-gray-400 font-mono">
                    ID: {code.id.slice(0, 8)}...
                  </p>
                </div>
              </div>
            ))}
          </div>
        )}
      </div>
    </div>
  );
}


